 1	import React, { FC } from 'react';
 2	import { useParams } from 'react-router-dom-v5-compat';
 3	
 4	import HorizontalNavbar from '@kubevirt-utils/components/HorizontalNavbar/HorizontalNavbar';
 5	import { SidebarEditorProvider } from '@kubevirt-utils/components/SidebarEditor/SidebarEditorContext';
 6	import { Stack, StackItem } from '@patternfly/react-core';
 7	
 8	import { useWizardVMContext } from '../utils/WizardVMContext';
 9	
10	import { WizardEmptyState } from './components/WizardEmptyState';
11	import { WizardFooter } from './components/WizardFooter';
12	import { WizardHeader } from './components/WizardHeader';
13	import { wizardNavPages } from './tabs';
14	
15	import './Wizard.scss';
16	
17	const Wizard: FC = () => {
18	  const { ns } = useParams<{ ns: string }>();
19	  const { vm } = useWizardVMContext();
20	
21	  if (!vm) return <WizardEmptyState namespace={ns} />;
22	
23	  return (
24	    <SidebarEditorProvider>
25	      <Stack hasGutter>
26	        <WizardHeader namespace={ns} />
27	        <StackItem className="vm-wizard-body" isFilled>
28	          <HorizontalNavbar loaded pages={wizardNavPages} vm={vm} />
29	        </StackItem>
30	        <WizardFooter namespace={ns} />
31	      </Stack>
32	    </SidebarEditorProvider>
33	  );
34	};
35	export default Wizard;

